		// Header
		////////////////////////////////////////////////////////////////////////////////////////////////	
		adm_header($object, hive__hsc($object["hive_mode_config"]["lang"]->translate("site_title")));
		echo sf__theme_title(hive__hsc($object["hive_mode_config"]["lang"]->translate("site_title")), hive__hsc($object["hive_mode_config"]["lang"]->translate("site_heading_text")));

